from pathlib import Path

root = Path(r"C:\Users\Gebruiker\Rezzerv_Github")
pre = root / "backend/app/receipt_ingestion/preprocessing/receipt_image_preprocessing.py"
req = root / "backend/requirements.txt"

pre.write_text('from __future__ import annotations\n\nfrom dataclasses import asdict, dataclass, field\nfrom io import BytesIO\nimport os\nfrom pathlib import Path\nimport tempfile\nfrom typing import Any\n\nfrom PIL import Image, ImageOps\n\ntry:\n    from rembg import remove as rembg_remove\nexcept Exception:\n    rembg_remove = None\n\ntry:\n    from paddleocr import DocPreprocessor\nexcept Exception:\n    DocPreprocessor = None\n\n\nIMAGE_SUFFIXES = {".jpg", ".jpeg", ".png", ".webp", ".bmp"}\n\n\n@dataclass\nclass ReceiptImagePreprocessingDecision:\n    preprocessing_step: str\n    selected_route: str\n    applied_steps: list[str]\n    fallback_reason: list[str]\n    perspective_normalization: dict[str, Any] | None\n    diagnostics: dict[str, Any] = field(default_factory=dict)\n\n    def to_dict(self) -> dict[str, Any]:\n        return asdict(self)\n\n\ndef _debug_dir() -> Path | None:\n    value = os.environ.get("REZZERV_RECEIPT_PREPROCESS_DEBUG_DIR")\n    if not value:\n        return None\n    path = Path(value)\n    path.mkdir(parents=True, exist_ok=True)\n    return path\n\n\ndef _save_debug(name: str, image: Image.Image, diagnostics: dict[str, Any]) -> None:\n    out = _debug_dir()\n    if out is None:\n        return\n    path = out / name\n    image.save(path)\n    diagnostics.setdefault("debug_files", []).append(str(path))\n\n\ndef _encode_png(image: Image.Image) -> bytes:\n    buf = BytesIO()\n    image.save(buf, format="PNG")\n    return buf.getvalue()\n\n\ndef _load_original(file_bytes: bytes, diagnostics: dict[str, Any]) -> Image.Image:\n    original = Image.open(BytesIO(file_bytes))\n    original = ImageOps.exif_transpose(original).convert("RGB")\n    diagnostics["original_size"] = [original.width, original.height]\n    _save_debug("00_input_original.png", original, diagnostics)\n    return original\n\n\ndef _rembg_neutralized(file_bytes: bytes, diagnostics: dict[str, Any]) -> tuple[Image.Image | None, str | None]:\n    if rembg_remove is None:\n        return None, "rembg_unavailable"\n\n    try:\n        rgba_bytes = rembg_remove(file_bytes)\n        rgba = Image.open(BytesIO(rgba_bytes)).convert("RGBA")\n        rgba = ImageOps.exif_transpose(rgba)\n        _save_debug("09_rembg_raw_rgba.png", rgba, diagnostics)\n\n        white = Image.new("RGBA", rgba.size, (255, 255, 255, 255))\n        neutralized = Image.alpha_composite(white, rgba).convert("RGB")\n        diagnostics["rembg"] = {\n            "route": "white_background_composite",\n            "size": [neutralized.width, neutralized.height],\n        }\n        _save_debug("10_rembg_neutralized.png", neutralized, diagnostics)\n        return neutralized, None\n    except Exception as exc:\n        return None, f"rembg_failed:{type(exc).__name__}"\n\n\ndef _candidate_image_files(directory: Path) -> list[Path]:\n    if not directory.exists():\n        return []\n    suffixes = {".png", ".jpg", ".jpeg", ".webp", ".bmp"}\n    files = [p for p in directory.rglob("*") if p.is_file() and p.suffix.lower() in suffixes]\n    return sorted(files, key=lambda p: (p.stat().st_mtime, p.stat().st_size), reverse=True)\n\n\ndef _try_save_paddle_result(result: Any, out_dir: Path, diagnostics: dict[str, Any]) -> list[Path]:\n    saved_before = set(_candidate_image_files(out_dir))\n    attempts: list[dict[str, Any]] = []\n\n    for method_name in ("save_to_img", "save_to_image", "save_all"):\n        method = getattr(result, method_name, None)\n        if not callable(method):\n            continue\n        try:\n            method(str(out_dir))\n            attempts.append({"method": method_name, "ok": True})\n        except TypeError:\n            try:\n                method(save_path=str(out_dir))\n                attempts.append({"method": method_name, "ok": True, "signature": "save_path"})\n            except Exception as exc:\n                attempts.append({"method": method_name, "ok": False, "error": f"{type(exc).__name__}: {exc}"})\n        except Exception as exc:\n            attempts.append({"method": method_name, "ok": False, "error": f"{type(exc).__name__}: {exc}"})\n\n    diagnostics.setdefault("paddle_save_attempts", []).extend(attempts)\n    saved_after = set(_candidate_image_files(out_dir))\n    return sorted(saved_after - saved_before, key=lambda p: (p.stat().st_mtime, p.stat().st_size), reverse=True)\n\n\ndef _extract_image_from_paddle_object(obj: Any, diagnostics: dict[str, Any]) -> Image.Image | None:\n    # Paddle/PaddleX result object versions differ. Keep this defensive.\n    keys = ("output_img", "doc_preprocessor_res", "img", "image", "res_img", "processed_img")\n    diagnostics.setdefault("paddle_result_types", []).append(str(type(obj)))\n\n    if isinstance(obj, dict):\n        diagnostics.setdefault("paddle_result_keys", []).append(list(obj.keys())[:80])\n        for key in keys:\n            value = obj.get(key)\n            image = _extract_image_from_paddle_object(value, diagnostics) if value is not None else None\n            if image is not None:\n                return image\n\n    for attr in keys:\n        if hasattr(obj, attr):\n            try:\n                value = getattr(obj, attr)\n                image = _extract_image_from_paddle_object(value, diagnostics)\n                if image is not None:\n                    return image\n            except Exception:\n                pass\n\n    try:\n        import numpy as np\n        if isinstance(obj, np.ndarray):\n            arr = obj\n            if arr.ndim == 2:\n                return Image.fromarray(arr).convert("RGB")\n            if arr.ndim == 3:\n                if arr.shape[2] == 3:\n                    return Image.fromarray(arr.astype("uint8")).convert("RGB")\n                if arr.shape[2] == 4:\n                    return Image.fromarray(arr.astype("uint8"), "RGBA").convert("RGB")\n    except Exception:\n        pass\n\n    if isinstance(obj, Image.Image):\n        return obj.convert("RGB")\n\n    return None\n\n\ndef _paddle_doc_preprocess(image: Image.Image, diagnostics: dict[str, Any]) -> tuple[Image.Image | None, dict[str, Any] | None, str | None]:\n    if DocPreprocessor is None:\n        return None, None, "paddle_doc_preprocessor_unavailable"\n\n    with tempfile.TemporaryDirectory(prefix="rezzerv_r9_27a_") as tmp:\n        tmp_dir = Path(tmp)\n        input_path = tmp_dir / "rembg_neutralized.png"\n        out_dir = tmp_dir / "paddle_output"\n        out_dir.mkdir(parents=True, exist_ok=True)\n        image.save(input_path)\n\n        try:\n            processor = DocPreprocessor(\n                use_doc_orientation_classify=True,\n                use_doc_unwarping=True,\n            )\n        except Exception as exc:\n            return None, None, f"paddle_docpreprocessor_init_failed:{type(exc).__name__}"\n\n        try:\n            prediction = processor.predict(str(input_path))\n            results = list(prediction) if not isinstance(prediction, list) else prediction\n        except Exception as exc:\n            return None, None, f"paddle_docpreprocessor_predict_failed:{type(exc).__name__}"\n\n        diagnostics["paddle_docpreprocessor"] = {\n            "result_count": len(results),\n            "result_types": [str(type(item)) for item in results],\n        }\n\n        for idx, result in enumerate(results):\n            image_from_object = _extract_image_from_paddle_object(result, diagnostics)\n            if image_from_object is not None:\n                _save_debug(f"20_paddle_docpreprocessor_object_{idx}.png", image_from_object, diagnostics)\n                return image_from_object, {"source": "DocPreprocessor", "result_index": idx, "extraction": "object"}, None\n\n            saved_files = _try_save_paddle_result(result, out_dir, diagnostics)\n            diagnostics.setdefault("paddle_saved_files", []).extend(str(p) for p in saved_files)\n            for saved in saved_files:\n                try:\n                    candidate = Image.open(saved).convert("RGB")\n                    _save_debug(f"21_paddle_docpreprocessor_saved_{idx}_{saved.name}", candidate, diagnostics)\n                    return candidate, {"source": "DocPreprocessor", "result_index": idx, "extraction": "saved_file", "file": str(saved)}, None\n                except Exception:\n                    continue\n\n        return None, {"source": "DocPreprocessor", "result_count": len(results)}, "paddle_docpreprocessor_no_image_output"\n\n\ndef _is_visually_usable(candidate: Image.Image, reference: Image.Image, diagnostics: dict[str, Any]) -> tuple[bool, str | None]:\n    gray = ImageOps.grayscale(candidate)\n    hist = gray.histogram()\n    total = sum(hist) or 1\n    near_white_ratio = sum(hist[248:]) / total\n    near_black_ratio = sum(hist[:8]) / total\n\n    diagnostics["paddle_candidate_quality"] = {\n        "size": [candidate.width, candidate.height],\n        "near_white_ratio": near_white_ratio,\n        "near_black_ratio": near_black_ratio,\n        "reference_size": [reference.width, reference.height],\n    }\n\n    if candidate.width < 300 or candidate.height < 500:\n        return False, "paddle_output_too_small"\n    if near_white_ratio > 0.985:\n        return False, "paddle_output_nearly_all_white"\n    if near_black_ratio > 0.985:\n        return False, "paddle_output_nearly_all_black"\n\n    return True, None\n\n\ndef apply_receipt_image_preprocessing(file_bytes: bytes, filename: str) -> tuple[bytes, ReceiptImagePreprocessingDecision]:\n    """R9-27A: rembg + Paddle DocPreprocessor, fallback to rembg-only.\n\n    This deliberately removes custom geometry decisions from the main route.\n    """\n    diagnostics: dict[str, Any] = {"filename": filename}\n    suffix = Path(filename or "").suffix.lower()\n\n    if suffix and suffix not in IMAGE_SUFFIXES:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original",\n            [],\n            ["unsupported_image_suffix"],\n            None,\n            diagnostics,\n        )\n\n    try:\n        original = _load_original(file_bytes, diagnostics)\n    except Exception as exc:\n        return file_bytes, ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original_bytes_fallback",\n            [],\n            [f"image_decode_failed:{type(exc).__name__}"],\n            None,\n            diagnostics,\n        )\n\n    rembg_image, rembg_reason = _rembg_neutralized(file_bytes, diagnostics)\n    if rembg_image is None:\n        _save_debug("40_final_runtime_preprocessed.png", original, diagnostics)\n        return _encode_png(original), ReceiptImagePreprocessingDecision(\n            "receipt_image_preprocessing",\n            "original_paddle_skipped",\n            [],\n            [rembg_reason or "rembg_failed"],\n            None,\n            diagnostics,\n        )\n\n    paddle_image, perspective, paddle_reason = _paddle_doc_preprocess(rembg_image, diagnostics)\n    if paddle_image is not None:\n        ok, reject_reason = _is_visually_usable(paddle_image, rembg_image, diagnostics)\n        if ok:\n            _save_debug("40_final_runtime_preprocessed.png", paddle_image, diagnostics)\n            _save_debug("50_final_ocr_input.png", ImageOps.grayscale(paddle_image), diagnostics)\n            diagnostics["final_size"] = [paddle_image.width, paddle_image.height]\n            return _encode_png(paddle_image), ReceiptImagePreprocessingDecision(\n                "receipt_image_preprocessing",\n                "R9-27A_rembg_paddle_docpreprocessor",\n                ["rembg_remove_background", "paddle_doc_orientation_classify", "paddle_doc_unwarping"],\n                [],\n                perspective,\n                diagnostics,\n            )\n        paddle_reason = reject_reason or "paddle_output_rejected"\n\n    # Safe fallback: keep proven rembg output rather than custom guessing.\n    _save_debug("40_final_runtime_preprocessed.png", rembg_image, diagnostics)\n    _save_debug("50_final_ocr_input.png", ImageOps.grayscale(rembg_image), diagnostics)\n    diagnostics["final_size"] = [rembg_image.width, rembg_image.height]\n    return _encode_png(rembg_image), ReceiptImagePreprocessingDecision(\n        "receipt_image_preprocessing",\n        "R9-27A_rembg_only_paddle_fallback",\n        ["rembg_remove_background", "white_background_composite"],\n        [paddle_reason or "paddle_docpreprocessor_unavailable_or_no_output"],\n        perspective,\n        diagnostics,\n    )\n', encoding="utf-8")

requirements = req.read_text(encoding="utf-8")
requirements = requirements.replace("rembg>=2.0,<3\n", "")
if "rembg[cpu]>=2.0,<3" not in requirements:
    if not requirements.endswith("\n"):
        requirements += "\n"
    requirements += "rembg[cpu]>=2.0,<3\n"
req.write_text(requirements, encoding="utf-8")

print("R9-27A toegepast: rembg + Paddle DocPreprocessor met veilige fallback naar rembg-only.")
